'use client'

import Image from 'next/image'
import { X, ChevronLeft, ChevronRight } from 'lucide-react'
import { useState } from 'react'

interface TheoryImage {
  url: string
  caption: string
}

interface Theory {
  id: number
  title: string
  shortDesc: string
  content: string
  images: TheoryImage[]
  keyPoints: string[]
}

interface TheoryCardProps {
  theory: Theory
}

export default function TheoryCard({ theory }: TheoryCardProps) {
  const [isOpen, setIsOpen] = useState(false)
  const [currentImageIndex, setCurrentImageIndex] = useState(0)

  const handlePrevImage = () => {
    setCurrentImageIndex((prev) => 
      prev === 0 ? theory.images.length - 1 : prev - 1
    )
  }

  const handleNextImage = () => {
    setCurrentImageIndex((prev) => 
      prev === theory.images.length - 1 ? 0 : prev + 1
    )
  }

  const currentImage = theory.images[currentImageIndex]

  return (
    <>
      <button
        onClick={() => setIsOpen(true)}
        className="bg-white rounded-lg border border-border shadow-sm hover:shadow-lg transition overflow-hidden text-left w-full p-6 hover:border-primary/50"
      >
        <div className="flex flex-col gap-2">
          <h3 className="text-xl font-bold text-foreground">{theory.title}</h3>
          <p className="text-muted-foreground text-sm">{theory.shortDesc}</p>
          <p className="text-primary text-sm font-medium mt-2">Nhấp để xem chi tiết →</p>
        </div>
      </button>

      {/* Modal Popup */}
      {isOpen && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50"
          onClick={() => setIsOpen(false)}
        >
          <div
            className="bg-white rounded-lg shadow-2xl w-full max-w-[95vw] md:max-w-4xl lg:max-w-5xl h-[92vh] md:h-[94vh] flex flex-col overflow-hidden"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Header - Sticky */}
            <div className="bg-gradient-to-r from-primary to-accent text-white p-6 flex justify-between items-start gap-4 flex-shrink-0">
              <div>
                <h2 className="text-3xl font-bold">{theory.title}</h2>
                <p className="text-white/90 mt-2">{theory.shortDesc}</p>
              </div>
              <button
                onClick={() => setIsOpen(false)}
                className="flex-shrink-0 p-1 hover:bg-white/20 rounded-lg transition"
                aria-label="Đóng"
              >
                <X className="w-6 h-6" />
              </button>
            </div>

            {/* Content - Scrollable */}
            <div className="overflow-y-auto flex-1 p-6">
              <div className="space-y-6">
                {/* Image Carousel */}
                <div className="space-y-3">
                  <div className="relative w-full h-80 bg-muted rounded-lg overflow-hidden">
                    <Image
                      key={currentImageIndex}
                      src={currentImage.url}
                      alt={currentImage.caption}
                      fill
                      className="object-cover"
                      priority={false}
                    />
                  </div>

                  {/* Image Caption */}
                  <div className="bg-secondary/50 rounded-lg p-4 border border-primary/20">
                    <p className="text-sm text-foreground italic">{currentImage.caption}</p>
                  </div>

                  {/* Image Navigation */}
                  {theory.images.length > 1 && (
                    <div className="flex items-center justify-between gap-3">
                      <button
                        onClick={handlePrevImage}
                        className="bg-primary hover:bg-primary/90 text-white p-2 rounded-lg transition flex-shrink-0"
                        aria-label="Ảnh trước"
                      >
                        <ChevronLeft className="w-5 h-5" />
                      </button>
                      <span className="text-sm text-muted-foreground text-center flex-1">
                        {currentImageIndex + 1} / {theory.images.length}
                      </span>
                      <button
                        onClick={handleNextImage}
                        className="bg-primary hover:bg-primary/90 text-white p-2 rounded-lg transition flex-shrink-0"
                        aria-label="Ảnh tiếp theo"
                      >
                        <ChevronRight className="w-5 h-5" />
                      </button>
                    </div>
                  )}
                </div>

                {/* Main Content */}
                <div>
                  <h3 className="font-semibold text-foreground mb-2">Nội dung chi tiết:</h3>
                  <p className="text-foreground leading-relaxed">{theory.content}</p>
                </div>

                {/* Key Points */}
                <div className="bg-secondary/50 rounded-lg p-6 border border-primary/20">
                  <h4 className="font-bold text-foreground mb-4">Điểm chính:</h4>
                  <ul className="space-y-3">
                    {theory.keyPoints.map((point, index) => (
                      <li key={index} className="flex gap-3">
                        <span className="text-accent font-bold flex-shrink-0 text-xl">▸</span>
                        <span className="text-foreground">{point}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              </div>
            </div>

            {/* Footer - Sticky */}
            <div className="bg-white border-t border-border p-6 flex-shrink-0">
              <button
                onClick={() => setIsOpen(false)}
                className="w-full bg-primary hover:bg-primary/90 text-white font-semibold py-3 px-6 rounded-lg transition"
              >
                Đóng
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  )
}
