'use client'

import { Check, X } from 'lucide-react'

interface Quiz {
  id: number
  question: string
  options: string[]
  correctIndex: number
  explanation: string
}

interface QuizCardProps {
  quiz: Quiz
  selectedAnswer: number
  onSelectAnswer: (index: number) => void
}

export default function QuizCard({ quiz, selectedAnswer, onSelectAnswer }: QuizCardProps) {
  const isAnswered = selectedAnswer !== -1
  const isCorrect = isAnswered && selectedAnswer === quiz.correctIndex

  return (
    <div className="space-y-6">
      {/* Question */}
      <h3 className="text-2xl font-bold text-foreground">{quiz.question}</h3>

      {/* Options */}
      <div className="space-y-3">
        {quiz.options.map((option, index) => {
          const isSelected = selectedAnswer === index
          const isCorrectOption = index === quiz.correctIndex
          const showCorrect = isAnswered && isCorrectOption
          const showIncorrect = isAnswered && isSelected && !isCorrect

          let bgClass = 'bg-white hover:bg-secondary/30'
          let borderClass = 'border-border'
          let textClass = 'text-foreground'

          if (showCorrect) {
            bgClass = 'bg-green-50 hover:bg-green-50'
            borderClass = 'border-green-500'
            textClass = 'text-green-900'
          } else if (showIncorrect) {
            bgClass = 'bg-red-50 hover:bg-red-50'
            borderClass = 'border-red-500'
            textClass = 'text-red-900'
          } else if (isSelected && !isAnswered) {
            bgClass = 'bg-primary/10'
            borderClass = 'border-primary'
          }

          return (
            <button
              key={index}
              onClick={() => onSelectAnswer(index)}
              disabled={isAnswered}
              className={`w-full p-4 rounded-lg border-2 text-left font-medium transition ${bgClass} border-${borderClass} ${textClass} ${
                isAnswered ? 'cursor-default' : 'cursor-pointer'
              }`}
            >
              <div className="flex items-center gap-3">
                <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center flex-shrink-0 ${
                  showCorrect ? 'border-green-500 bg-green-500' : 
                  showIncorrect ? 'border-red-500 bg-red-500' :
                  isSelected ? 'border-primary bg-primary' : 'border-muted'
                }`}>
                  {showCorrect && <Check className="w-4 h-4 text-white" />}
                  {showIncorrect && <X className="w-4 h-4 text-white" />}
                </div>
                <span>{option}</span>
              </div>
            </button>
          )
        })}
      </div>

      {/* Explanation */}
      {isAnswered && (
        <div className={`rounded-lg p-4 ${isCorrect ? 'bg-green-50 border border-green-200' : 'bg-red-50 border border-red-200'}`}>
          <p className={`font-semibold mb-2 ${isCorrect ? 'text-green-900' : 'text-red-900'}`}>
            {isCorrect ? '✓ Chính xác!' : '✗ Không chính xác'}
          </p>
          <p className={`text-sm ${isCorrect ? 'text-green-800' : 'text-red-800'}`}>
            {quiz.explanation}
          </p>
        </div>
      )}
    </div>
  )
}
